INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('6c69d4b8-7143-5dde-8b9c-572b881de436', 'dc7b14dd-223c-4fd2-bc3c-3271046f78bf', 'The weather forecast predicted heavy rain, so we prepared our outdoor equipment ___.', '天氣預報預測會有大雨，所以我們相應地準備了戶外設備。', 'accordingly', 'accidentally', 'annually', 'suddenly', 'ac (朝向) + cord (心/一致) + ly (副詞字尾) → 朝向一致的方向 → 相應地、因此。', '根據 (according) 預報的情況，去做 (ly) 相應的動作 → accordingly。', '2026-07-06 16:54:45', '2026-07-06 16:54:45'),
('9bd65a5a-6f43-599e-ae19-f87bc6b97d5e', 'fb8e815f-b263-43a9-8191-265904c1f5a8', 'The sun ___ rises in the east.', '太陽總是從東邊升起。', 'always', 'sadly', 'easily', 'loudly', '由 all (全部) 與 ways (路徑/方法) 組成。', '每一條路 (all ways) 都會發生這件事 → 總是。', '2026-07-06 13:59:05', '2026-07-06 13:59:05'),
('b5f1da72-dee6-5899-a1f6-299360248342', '22345af2-07f0-4ebc-a220-2a8e8fd095d3', 'The committee decided to ___ the outdated law to better reflect the needs of modern society.', '委員會決定修訂那項過時的法律，以更好地反映現代社會的需求。', 'amend', 'avoid', 'admire', 'absorb', '字根 mend 有「修補、改善」的意思，加上前綴 a- 形成動詞 amend，意為「修訂、修改」。', '可以記成 a + mend (修補) → 去修補、去改善（法律或計畫）。', '2026-07-06 20:45:31', '2026-07-06 20:45:31'),
('e906caaa-020a-534d-aa53-79bb1373d456', 'ac13fde8-c53f-49dd-bdca-618241eb7414', 'We are happy ___ excited.', '我們既開心又興奮。', 'and', 'but', 'or', 'so', '連接詞，用於連接兩個對等的形容詞。', 'and 把兩種心情連在一起。', '2026-07-05 08:29:29', '2026-07-05 08:29:29'),
('ba62b944-a676-5f0d-a78d-dbe2ceefb62a', '4ea030c9-a049-4e02-9ac6-99fb4b9eaab2', 'Please remember to ___ a copy of your ID to the completed application form.', '請記得在填寫完的申請表後附上一份身分證影本。', 'attach', 'remove', 'create', 'ignore', 'ad- (趨向/向) + tach (固定/緊固) → 朝向某物固定 → 附上、貼上。', '想像 ''at'' (在) + ''tach'' (發音像 tack 釘子) → 用釘子把東西固定在某處 → 附上、貼上。', '2026-07-07 01:58:51', '2026-07-07 01:58:51'),
('18cc1b62-7052-5887-a60c-bb8d28f47482', 'd8e542dd-0a94-4075-a740-5cf81b84866e', 'All students are required to ___ the orientation session held in the auditorium this Friday.', '所有學生都被要求參加這週五在禮堂舉行的說明會。', 'attend', 'ignore', 'provide', 'achieve', 'ad (朝向) + tend (伸展) → 伸向某個地方或事情 → 出席、參加。', '把你的注意力 (attention) 伸向某個會議 → 參加、出席。', '2026-07-07 02:11:03', '2026-07-07 02:11:03'),
('9f5b0393-e1e2-5e97-9d32-d8318ba17e66', 'c5a6bb6c-11be-4f15-9ea7-f6b983edff63', 'Philosophers often debate the mystery of ___.', '哲學家常討論「存在」之謎。', 'being', 'logic', 'truth', 'reason', 'be (存在) + ing (名詞字尾) → 存在、生命體、本質。', '想像「being」就是「正在存在著的狀態」→ 存在、生命。', '2026-07-05 14:01:43', '2026-07-05 14:01:43'),
('63b4174a-a643-53e2-a49c-dcaa8e07608a', '0c540794-c18e-48dc-964e-63a65a1ec1ee', 'The shop is ___ the bank and the school.', '這間商店在銀行和學校之間。', 'between', 'among', 'behind', 'near', 'be- (在...之間) + tween (兩者之中) → 用於兩者之間。', 'A and B 之間，選 between。', '2026-07-05 07:06:19', '2026-07-05 07:06:19'),
('c5ac30f1-e1e4-50c3-8a73-778c475ca492', 'fae37cff-858e-40cb-9fed-8c6f4676b680', 'Let''s take a short ___ before the next class.', '在下一堂課之前，讓我們休息一下吧。', 'break', 'gift', 'dream', 'trip', 'break 當名詞時，常用於 take a break，表示「休息時間」。', 'break 就像「破」除忙碌，去做休息。', '2026-07-07 08:16:17', '2026-07-07 08:16:17'),
('1f55161a-371a-5f94-bf33-0ee9f72b1332', '005f2d40-045e-4b03-b548-d6244e7fac28', 'I usually have a bowl of ___ with milk for breakfast.', '我早餐通常會吃一碗加牛奶的麥片。', 'cereal', 'bread', 'soup', 'cake', 'cereal 源自拉丁語 cerealis，意指與穀物 (grain) 有關。', '想像早餐時，用碗 (bowl) 裝著麥片 (cereal) 並倒入牛奶 (milk)。', '2026-07-07 03:00:51', '2026-07-07 03:00:51'),
('21d7fe82-9c4b-5291-abd3-618d51315c0e', '04480e83-0da6-4a6c-b2ba-ff01569b0f47', 'I always ___ my room on Saturdays.', '我每個星期六都會打掃我的房間。', 'clean', 'cook', 'sing', 'jump', 'clean 為動詞，表示『打掃、清理』。', 'clean 的動詞用法就是進行『清』理工作。', '2026-07-07 04:30:27', '2026-07-07 04:30:27'),
('4fa47cb7-b7d5-55d9-8909-4deb965a8a16', '898768e6-3775-4d53-884e-7131238c3c9e', 'You should ask the ___ at the front desk for more information.', '你應該詢問櫃檯的工作人員以獲得更多資訊。', 'clerk', 'baker', 'dancer', 'actor', 'clerk 為名詞，指在辦公室或商店工作的辦事員。', 'clerk 看到 ''cl'' 聯想 ''clean''，店裡的職員把櫃檯維持得很乾淨。', '2026-07-07 04:33:09', '2026-07-07 04:33:09'),
('5b2569e7-68fe-5718-95c2-11f07d11214e', '92394316-66d3-4c91-9163-c7b1e3cb81d8', 'If we don''t water the plants, they will ___ soon.', '如果我們不給植物澆水，它們很快就會枯死。', 'die', 'sing', 'run', 'eat', 'die 作為動詞，表示「死亡」或植物「枯萎」。', '可以想像一個很「呆」的人，因為沒力氣而「死」掉了。', '2026-07-07 03:54:53', '2026-07-07 03:54:53'),
('ff0fb17c-342d-549b-a4ad-7e1eedf71bbe', 'f223437e-010f-4aaa-bee2-733135ae64fa', 'My mother ___ cook dinner on Saturdays.', '我媽媽在星期六不做晚餐。', 'doesn''t', 'aren''t', 'am not', 'weren''t', 'does (助動詞) + not (否定詞) 的縮寫。', '單數主詞 (My mother) → doesn''t + 原形動詞。', '2026-07-07 05:00:16', '2026-07-07 05:00:16'),
('3cb08d9f-afae-59e2-800c-27c03d3fa97a', '814d7410-69b9-4ed3-a3a5-5c5611b43e6e', 'We can ___ many interesting things at the science museum.', '我們可以在科學博物館體驗很多有趣的事。', 'experience', 'buy', 'cook', 'wash', 'ex (向外) + peri (嘗試) → 向外嘗試事物', '走出家門向外 (ex) 嘗試 (peri) 新事物，就是「經歷」或「體驗」。', '2026-07-07 05:24:08', '2026-07-07 05:24:08'),
('8cdee92e-2a5c-5944-ba15-989bc0645292', 'fb317c3c-8446-4ee4-9bfc-798b3e8a0110', 'We are planning to visit Japan ___ the summer.', '我們計畫在夏天去日本旅遊。', 'in', 'on', 'at', 'through', '用於較長的時間段（如季節、月份、年份）。', '包含在一段大的時間範圍內。', '2026-07-05 10:04:42', '2026-07-05 10:04:42'),
('dcde15d3-8af3-5477-aa03-2fe86da0b2c2', '69c72296-40c5-4d3c-8b3a-6a62df6576c3', 'Excuse me, I think you have picked up ___ wallet by mistake.', '不好意思，我想你拿錯了我的錢包。', 'my', 'your', 'her', 'their', '所有格形容詞 (possessive adjective)', 'my + 名詞 → 我的...', '2026-07-05 14:13:13', '2026-07-05 14:13:13'),
('35d18fea-d369-59b8-8bd2-2ec69926e776', '1621adb1-9e24-4e8a-829c-9d14e9be90e1', '___ the rain stops, we can continue our hiking trip.', '當雨停時，我們就可以繼續我們的健行之旅。', 'when', 'although', 'unless', 'since', 'when 在此作為連接詞，引導一個表示時間的副詞子句。', '當 A 發生時 → when A happens', '2026-07-06 11:06:15', '2026-07-06 11:06:15');
